class Solution {
public:
    int nextBeautifulNumber(int n) {
        while (true) {
            n++;
            string s = to_string(n);
            map<char, int> counts;
            for (char c : s) {
                counts[c]++;
            }
            bool balanced = true;
            for (auto it : counts) {
                if (it.second != it.first - '0') {
                    balanced = false;
                    break;
                }
            }
            if (balanced) {
                return n;
            }
        }
    }
};
```
